import { Pool, type PoolConfig } from "pg";

let dbUnavailableLogged = false;

function buildPoolConfig(): PoolConfig {
  const connectionString =
    process.env.DATABASE_URL || "postgresql://postgres:postgres@127.0.0.1:5432/video_automation";

  const config: PoolConfig = { connectionString };

  if (
    connectionString.includes("neon.tech") ||
    connectionString.includes("render.com") ||
    process.env.DATABASE_SSL === "1"
  ) {
    config.ssl = { rejectUnauthorized: false };
  }

  return config;
}

export const db = new Pool(buildPoolConfig());

db.on("error", (error) => {
  console.error("[db] PostgreSQL pool error", error);
});

export async function isDatabaseAvailable() {
  try {
    await db.query("SELECT 1");
    return true;
  } catch (error) {
    if (!dbUnavailableLogged) {
      dbUnavailableLogged = true;
      console.warn(
        "[db] PostgreSQL is unavailable. Falling back to empty task lists until it is reachable.",
        error,
      );
    }
    return false;
  }
}

export async function ensureTaskTable() {
  const available = await isDatabaseAvailable();
  if (!available) {
    return false;
  }

  try {
    await db.query(`
      CREATE TABLE IF NOT EXISTS media_tasks (
        id TEXT PRIMARY KEY,
        status TEXT NOT NULL,
        progress INTEGER NOT NULL,
        created_at TIMESTAMPTZ NOT NULL,
        updated_at TIMESTAMPTZ NOT NULL,
        started_at TIMESTAMPTZ,
        completed_at TIMESTAMPTZ,
        error_message TEXT,
        storage_key TEXT,
        storage_path TEXT,
        output_key TEXT,
        retry_count INTEGER NOT NULL DEFAULT 0,
        max_retries INTEGER NOT NULL DEFAULT 2,
        last_heartbeat_at TIMESTAMPTZ,
        message TEXT NOT NULL,
        input_json JSONB NOT NULL,
        assets_json JSONB NOT NULL DEFAULT '[]'::jsonb
      );
    `);
    return true;
  } catch (error) {
    console.warn("[db] Failed to create media_tasks table", error);
    return false;
  }
}
